'use client'

import { CSSProperties, MouseEventHandler } from 'react'

type PatternGeometryProps = {
  instanceId: string
  onHoverChange?: (groupOrPathId: string | null) => void
  activeGroup?: string | null
}

/**
 * Note:
 * Regex for updating all id attributes in the svg:
 * - FIND:
 * > ``` id="([^"]+)" ```
 * - REPLACE:
 * > ``` id={`$1-${instanceId}`} ```
 */

export const DefaultHitBoxStyles: CSSProperties = {
  opacity: 0,
  fill: '#000000',
  fillOpacity: 0,
  stroke: '#000000',
  strokeWidth: 1,
  strokeOpacity: 0,
  pointerEvents: 'fill',
}

